//   이전(1.9.288): __filename regex self-count — 도구 정의가 소스에 있어야만 동작(취약, Codex #5). 이제 tools/list 와 동일 배열을 직접 카운트.
function _mcpToolCount() {
  try { return require('../lib/mcp-tools').length; } catch { return 0; }
}
function absRoot(p) { return path.resolve(p || process.cwd()); }
function exists(p) { return fs.existsSync(p); }
function read(p) {
  // 1.9.147: UTF-8 BOM 자동 strip — Windows PowerShell Out-File 등이 BOM 붙이는 경우 JSON.parse 실패 방지
  const text = fs.readFileSync(p, 'utf8');
  return text.charCodeAt(0) === 0xFEFF ? text.slice(1) : text;
}
function readBuf(p) { return fs.readFileSync(p); }
function mkdirp(p) { fs.mkdirSync(p, { recursive: true }); }
// 1.9.298 (UR-0038, 외부리뷰 3중수렴): 원자적 쓰기 — temp 파일에 기록 후 rename(원자 교체)으로 부분쓰기 손상 방지.
//   crash/타임아웃 kill/동시쓰기 중에도 대상 파일에 깨진 부분파일이 남지 않음 ('메모리 항상 보존' 코드 보증).
//   rename 은 동일 디렉토리(=동일 FS) 라 POSIX/NTFS 모두 원자적(Node renameSync = MOVEFILE_REPLACE_EXISTING).
//   temp 이름은 확장자 끝이 아니라 .tmp-PID-SEQ 라 *.md glob 에 안 걸림. 실패 시 temp 정리.
let _writeSeq = 0;
function writeUtf8(p, s) {
  mkdirp(path.dirname(p));
  const tmp = `${p}.tmp-${process.pid}-${++_writeSeq}`;
  try {
    fs.writeFileSync(tmp, s, { encoding: 'utf8' });
    fs.renameSync(tmp, p);
  } catch (e) {
    try { if (fs.existsSync(tmp)) fs.unlinkSync(tmp); } catch {}
    throw e;
  }
}
function append(p, s) { mkdirp(path.dirname(p)); fs.appendFileSync(p, s, 'utf8'); }
// 1.9.303 (UR-0043, 외부리뷰): 동기 sleep (Atomics.wait, 실패 시 busy-wait 폴백).
function _sleepSyncMs(ms) {
  try { Atomics.wait(new Int32Array(new SharedArrayBuffer(4)), 0, 0, Math.max(1, ms | 0)); }
  catch { const end = Date.now() + ms; while (Date.now() < end) {} }
}
// 1.9.303 (UR-0043, 외부리뷰 Codex/Opus): read-modify-write lost-update 방지 advisory 락.
//   O_EXCL(wx) 원자적 생성으로 상호배제. 다른 프로세스가 보유 중이면 짧게 대기 후 재시도.
//   stale(보유 프로세스 crash) 은 staleMs 초과 시 탈취. 타임아웃(maxWaitMs) 시 락 없이 진행(원자쓰기로 손상은 이미 방지, lost-update 만 rare 노출).
const _heldLocks = new Set();  // 프로세스 내 재진입 추적 (중첩 _withLock 데드락 방지)
function _withLock(targetPath, fn, opts = {}) {
  const lockPath = targetPath + '.lock';
  if (_heldLocks.has(lockPath)) return fn();  // 이미 이 프로세스가 보유 → 재진입(중첩 호출 안전)
  const maxWaitMs = opts.maxWaitMs || 5000;
  const staleMs = opts.staleMs || 30000;
  try { mkdirp(path.dirname(lockPath)); } catch {}
  const start = Date.now();
  let held = false;
  while (Date.now() - start <= maxWaitMs) {
    try { const fd = fs.openSync(lockPath, 'wx'); fs.closeSync(fd); held = true; break; }  // 원자적 배타 생성
    catch (e) {
      if (e.code !== 'EEXIST') break;  // 예기치 못한 오류 → 락 없이 진행
      try { const st = fs.statSync(lockPath); if (Date.now() - st.mtimeMs > staleMs) { fs.unlinkSync(lockPath); continue; } } catch {}
      _sleepSyncMs(15 + Math.floor((Date.now() - start) / 50));  // 점증 backoff
    }
  }
  if (held) _heldLocks.add(lockPath);
  try { return fn(); }
  finally { if (held) { _heldLocks.delete(lockPath); try { fs.unlinkSync(lockPath); } catch {} } }
}
function rel(root, p) { return path.relative(root, p).replace(/\\/g, '/') || '.'; }
function today() { return new Date().toISOString().slice(0, 10); }
function now() { return new Date().toISOString(); }
// 1.9.327 (UR-0025): _getLocalTz / _formatLocal → lib/pure-utils.js 로 이동 (순수 TZ/날짜 포맷, require 사용).
// 자동 모드 활성 여부 (R-XXXX every-round 룰 존재 시 true)
function _isAutoLoopActive(root) {
  try {
    const rules = readRules(root);
    return rules.some(r => r.status === 'active' && /every-round|every-session/i.test(r.trigger || ''));
  } catch { return false; }
}
function _getAutoLoopRule(root) {
  try {
    return readRules(root).find(r => r.status === 'active' && /every-round/i.test(r.trigger || '')) || null;
  } catch { return null; }
}
function arg(name, def = null) { const i = process.argv.indexOf(name); return i >= 0 ? (process.argv[i + 1] || true) : def; }
function has(name) { return process.argv.includes(name); }
function nonFlagArgs() {
  const out = [];
  const withValue = new Set(['--language','--skills','--path','--status','--progress','--goal','--reason','--next','--target','--token-env','--package','--out','--from','--repo','--id','--note','--evidence','--query','--limit','--action','--agent','--tool','--doc','--command','--capability','--before','--after','--display','--threshold','--trigger','--check','--set','--min-score','--include','--days','--gh-pages-src','--roadmap','--since','--agents','--model','--timeout','--retry-on-fail','--label','--score','--tokens','--alternatives','--impact','--tag','--surface','--depends-on','--affects','--co-changes-with','--files','--branch','--remote','--task-add','--next-action','--role','--provider','--env-var','--deploy','--token-lifetime-hours','--port','--secret','--keep']);
  const a = process.argv.slice(2);
  for (let i = 0; i < a.length; i++) {
    const x = a[i];
    if (x.startsWith('-')) { if (withValue.has(x) && a[i+1] && !a[i+1].startsWith('-')) i++; continue; }
    out.push(x);
  }
  return out;
}
function argAll(name) {
  const out = []; const a = process.argv;
  for (let i = 0; i < a.length; i++) if (a[i] === name && a[i+1] && !a[i+1].startsWith('-')) out.push(a[++i]);
  return out;
}
function detectProjectName(root) { try { const pkg = JSON.parse(read(path.join(root, 'package.json'))); if (pkg.name) return pkg.name; } catch {} return path.basename(root); }
// 1.9.269 (UR-0022): OS 시스템 언어 감지 — 신규 init(빈 디렉토리, 프로젝트 콘텐츠 없음)에서 OS locale 로 설치 언어 판별.
//   우선순위: POSIX 환경변수(LC_ALL>LC_CTYPE>LANG>LANGUAGE) > Intl ICU resolvedOptions().locale(Windows 등 LANG 미설정 시) > null.
//   순수 함수(부작용 0) — env 주입 가능(selftest). 판별 불가 시 null 반환 → 호출부가 en 폴백.
// _detectSystemLang → lib/pure-utils.js 로 이동 (1.9.274 UR-0025 1단계)
function detectLanguageValue(root, value = 'auto') {
  const v = String(value || 'auto').toLowerCase();
  if (v === 'ko' || v === 'en') return v;
  // ① 프로젝트 콘텐츠 한글 우선 — 콘텐츠가 있으면 그 의도를 존중 (기존 동작 보존).
  const candidates = ['README.md', 'docs/guideline.md', '.harness/project-brief.md', '.harness/plan.md'];
  let text = '';
  for (const c of candidates) { const p = path.join(root, c); if (exists(p)) text += read(p).slice(0, 3000); }
  if (/[가-힣]/.test(text)) return 'ko';
  // 1.9.269 (UR-0022): ② 콘텐츠가 비어있으면(신규/빈 디렉토리 init) OS 시스템 언어로 판별.
  //   콘텐츠가 있는데 한글이 아니면(영어 프로젝트) en 유지 — 기존 프로젝트 회귀 방지.
  if (text.trim().length === 0) {
    const sys = _detectSystemLang();
    if (sys) return sys;
  }
  // ③ en 폴백
  return 'en';
}
function fm(role, readWhen, updateWhen, body) {
  return `---\nleernessRole: ${role}\nreadWhen:\n${readWhen.map(x => '  - ' + x).join('\n')}\nupdateWhen:\n${updateWhen.map(x => '  - ' + x).join('\n')}\ndoNotStore:\n  - 실제 토큰\n  - 비밀번호\n  - 운영 쿠키\n  - 민감한 개인정보 원문\n---\n${MARK}\n${body}`;
}
function ask(question) {
  return new Promise(resolve => {
    const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
    // 1.9.190 (사용자 명시 BUG fix): readline 의 자체 SIGINT 처리 — Ctrl+C 시 즉시 종료.
    //   process.on('SIGINT') 핸들러는 readline raw mode 에 가려져 호출 안 됨 → 여기서 명시 처리.
    rl.on('SIGINT', () => {
      try { rl.close(); } catch {}
      process.stdout.write('\n  \x1b[31m✗ 설치 중단됨 (Ctrl+C)\x1b[0m\n');
      process.exit(130);
    });
    rl.question(question, answer => { rl.close(); resolve(String(answer || '').trim()); });
  });
}

